'use client';

import { useEffect, useRef } from 'react';

// Easing function for smooth mathematical tracking
function lerp(start: number, end: number, t: number) {
  return start * (1 - t) + end * t;
}

export function CursorLines() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let animationFrameId: number;
    
    const mouse = { x: -1000, y: -1000 };
    const smoothedMouse = { x: -1000, y: -1000 };

    const grid = 40;
    const lineLength = 12;

    interface Point {
      x: number;
      y: number;
      angle: number;
    }
    let points: Point[] = [];

    const initPoints = (width: number, height: number) => {
      points = [];
      const cols = Math.floor(width / grid) + 2;
      const rows = Math.floor(height / grid) + 2;
      
      const offsetX = (width - (cols - 1) * grid) / 2;
      const offsetY = (height - (rows - 1) * grid) / 2;

      for (let i = 0; i < cols; i++) {
        for (let j = 0; j < rows; j++) {
          points.push({
            x: offsetX + i * grid,
            y: offsetY + j * grid,
            angle: Math.sin((offsetX + i * grid) * 0.005) + Math.cos((offsetY + j * grid) * 0.005) // natural drift baseline
          });
        }
      }
    };

    const resize = () => {
      const rect = canvas.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      
      ctx.scale(dpr, dpr);
      initPoints(rect.width, rect.height);
    };

    resize();
    window.addEventListener('resize', resize);

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
      
      if (smoothedMouse.x === -1000) {
        smoothedMouse.x = mouse.x;
        smoothedMouse.y = mouse.y;
      }
    };

    window.addEventListener('mousemove', handleMouseMove);

    const render = () => {
      const rect = canvas.getBoundingClientRect();
      ctx.clearRect(0, 0, rect.width, rect.height);

      // We only apply heavy physics rotation if the mouse has physically moved over the screen
      const hasMouse = smoothedMouse.x !== -1000;

      if (hasMouse) {
        smoothedMouse.x = lerp(smoothedMouse.x, mouse.x, 0.12);
        smoothedMouse.y = lerp(smoothedMouse.y, mouse.y, 0.12);
      }

      for (let i = 0; i < points.length; i++) {
        const p = points[i];
        
        let targetAngle = p.angle;
        if (hasMouse) {
          const dx = smoothedMouse.x - p.x;
          const dy = smoothedMouse.y - p.y;
          targetAngle = Math.atan2(dy, dx);
        }

        // Calculate geometry to spin the shortest arc path
        let angleDiff = targetAngle - p.angle;
        angleDiff = Math.atan2(Math.sin(angleDiff), Math.cos(angleDiff));
        p.angle += angleDiff * 0.08; // smooth tension

        // Apply a sophisticated ambient glow to lines near the cursor trajectory
        const dxRaw = mouse.x - p.x;
        const dyRaw = mouse.y - p.y;
        const dist = Math.sqrt(dxRaw * dxRaw + dyRaw * dyRaw);
        
        const isClose = hasMouse && dist < 400;
        const intensity = isClose ? Math.pow(1 - dist / 400, 1.5) : 0; 

        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.angle);
        
        ctx.beginPath();
        ctx.moveTo(-lineLength / 2, 0);
        ctx.lineTo(lineLength / 2, 0);
        
        ctx.lineWidth = 1.5;
        
        // Base muted Zinc-300 grey. Highlight thickens opacity for a crisp hover depth.
        const baseAlpha = 0.25; 
        const focusAlpha = baseAlpha + (intensity * 0.45); 
        ctx.strokeStyle = `rgba(161, 161, 170, ${focusAlpha})`;
        
        ctx.lineCap = 'round';
        ctx.stroke();
        ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      window.removeEventListener('mousemove', handleMouseMove);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="absolute inset-0 w-full h-full pointer-events-none z-0"
      style={{ display: 'block' }}
    />
  );
}
