// ─── Animated Stack ──────────────────────────────────────────────────────────

function AnimatedStack({ steps, headline, intro }: { steps: Step[]; headline: string; intro?: string }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const prefersReduced = useReducedMotion();

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ['start start', 'end end'],
  });

  // Screen-size agnostic physics utilizing container percentages guarantees flawless overlap
  // Card moves from 150% (below) to 0% (locked). Overlap strictly begins exactly at 100%.
  const y1 = useTransform(scrollYProgress, [0.05, 0.30], ['150%', '0%']);
  const y2 = useTransform(scrollYProgress, [0.35, 0.60], ['150%', '0%']);
  const y3 = useTransform(scrollYProgress, [0.65, 0.90], ['150%', '0%']);

  // 150% to 100% spans exactly 1/3 of the 0.25 duration (0.083 progress).
  // By fading from 0 to 1 over just 0.06 progress length (0.05 -> 0.11), 
  // opacity completely solidifies BEFORE the card physically overlaps the previous layer!
  const opacity1 = useTransform(scrollYProgress, [0.05, 0.11], [0, 1]);
  const opacity2 = useTransform(scrollYProgress, [0.35, 0.41], [0, 1]);
  const opacity3 = useTransform(scrollYProgress, [0.65, 0.71], [0, 1]);

  const baseShadow = '0 8px 40px rgba(0,0,0,0.07), 0 1px 3px rgba(0,0,0,0.04)';
  const zeroShadow = '0 8px 40px rgba(0,0,0,0), 0 1px 3px rgba(0,0,0,0)';

  const shadow1 = useTransform(scrollYProgress, [0.28, 0.30], [baseShadow, zeroShadow]);
  const shadow2 = useTransform(scrollYProgress, [0.58, 0.60], [baseShadow, zeroShadow]);
  const shadow3 = useTransform(scrollYProgress, [0.88, 0.90], [baseShadow, zeroShadow]);

  const cards = [
    { y: undefined, opacity: undefined, shadow: baseShadow },
    { y: y1, opacity: opacity1, shadow: shadow1 },
    { y: y2, opacity: opacity2, shadow: shadow2 },
    { y: y3, opacity: opacity3, shadow: shadow3 },
  ];

  return (
    <div
      ref={containerRef}
      className="relative z-10 w-full" 
      style={{ height: '350vh' }}
    >
      <div className="sticky top-[60px] md:top-[80px] h-[calc(100vh-60px)] md:h-[calc(100vh-80px)] flex flex-col overflow-hidden">
        {/* Header firmly kept fixed on top during the animation */}
        <div className="pt-6 md:pt-8 pb-4 text-center flex-shrink-0 px-4 md:px-6">
          <h2 className="font-bold tracking-tight text-zinc-900 mb-2" style={{ fontSize: 'clamp(1.8rem, 4vw, 2.8rem)', lineHeight: 1.1 }}>
            {headline}
          </h2>
          {intro && <p className="text-sm text-zinc-500 max-w-xl mx-auto">{intro}</p>}
        </div>

        {/* Card area */}
        <div className="flex-1 flex items-start justify-center px-4 md:px-6">
          <div className="relative w-full max-w-[880px] mt-4 md:mt-12 h-[560px] md:h-[420px]">
            {steps.slice(0, NUM).map((step, i) => {
              const Visual = STEP_VISUALS[i];
              const card = cards[i];

              return (
                <motion.div
                  key={i}
                  className="absolute inset-0 rounded-2xl"
                  style={{
                    zIndex: i + 1,
                    y: prefersReduced ? '0%' : (card.y ?? '0%'),
                    opacity: prefersReduced ? 1 : (card.opacity ?? 1),
                    boxShadow: prefersReduced ? (i === 0 ? baseShadow : zeroShadow) : card.shadow,
                    willChange: 'transform, opacity, box-shadow',
                  }}
                >
                  <div className="relative z-10 w-full h-full rounded-2xl bg-[#FAFAF9]">
                    <StepCard step={step} index={i}>
                      {Visual ? <Visual /> : null}
                    </StepCard>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Main ────────────────────────────────────────────────────────────────────

export function StickyScroll({ headline, intro, steps }: StickyScrollProps) {
  return (
    <section style={{ background: '#FEFEFE' }}>
      <AnimatedStack steps={steps} headline={headline} intro={intro} />
    </section>
  );
}
